use core::{ffi::c_void, ptr};

fn clear_bss() {
    unsafe extern "C" {
        fn sbss();
        fn ebss();
    }
    unsafe {
        ptr::write_bytes(
            sbss as *const () as usize as *mut c_void,
            0,
            ebss as *const () as usize - sbss as *const () as usize,
        );
    }
}

#[unsafe(no_mangle)]
#[cfg(target_arch = "riscv64")]
#[unsafe(link_section = ".text.main")]
pub fn fake_main(hart_id: usize, dtb_address: usize) {
    use crate::arch::config::KERNEL_BASE_OFFSET;
    unsafe {
        core::arch::asm!("add sp, sp, {}", in(reg) KERNEL_BASE_OFFSET);
        core::arch::asm!(
            "lla t1, __global_pointer$",
            "add gp, t1, {offset}",
            offset = in(reg) KERNEL_BASE_OFFSET,
            lateout("t1") _,
        );
        core::arch::asm!("la t0, rust_main");
        core::arch::asm!("add t0, t0, {}", in(reg) KERNEL_BASE_OFFSET);
        core::arch::asm!("mv a0, {}", in(reg) hart_id);
        core::arch::asm!("mv a1, {}", in(reg) dtb_address);
        core::arch::asm!("jalr zero, 0(t0)");
    }
}

#[unsafe(no_mangle)]
pub fn rust_main(_hart_id: usize, _dtb_address: usize) -> ! {
    clear_bss();
    // RISC-V 先从启动汇编修正后的 gp 取运行时值；LoongArch 当前不依赖该寄存器。
    unsafe {
        let gp_runtime: usize;
        #[cfg(target_arch = "riscv64")]
        core::arch::asm!("mv {}, gp", out(reg) gp_runtime);
        #[cfg(target_arch = "loongarch64")]
        {
            gp_runtime = 0;
        }
        crate::arch::KERNEL_GP_RUNTIME = gp_runtime;
    }
    #[cfg(target_arch = "loongarch64")]
    crate::arch::timer::init_clock_freq();
    mm::init();

    // 这些 runtime_state 是内核全局表，不依赖用户文件系统内容，必须在 trap/scheduler
    // 和用户态切换前完成初始化。
    process::init_runtime_state();
    syscall::init_runtime_state();
    fs::init_runtime_state();

    trap::init();
    mm::activate_kernel_space();

    drivers::init_runtime_state();
    global_logger::init();
    if test_block_device() {
        fs::init_filesystems();
        user_init();
    } else {
        println!("No block device found, exiting...");
        shutdown(false);
    }
}

/// 启动用户态 init 程序，若缺失则关机。
fn user_init() -> ! {
    if process::try_exec_from_path("/init") {
        unreachable!("try_exec_from_path('/init') should not return on success");
    }
    println!("[boot] no user init entry found in fs");
    shutdown(false);
}

/// 测试块设备，返回是否成功
fn test_block_device() -> bool {
    use alloc::vec;
    use drivers::BLOCK_DEVICE;
    if !drivers::block_device_available() {
        return false;
    }
    // 可用性探测
    let mut buf = vec![0u8; 512];
    if let Some(device) = BLOCK_DEVICE.lock().as_mut() {
        device.read_block(0, &mut buf);
        true
    } else {
        false
    }
}

