#[derive(Clone, Copy, Debug, Default)]
pub struct KernelHeapStats {
    pub capacity: usize,
    pub current: usize,
    pub peak: usize,
    pub alloc_count: usize,
    pub dealloc_count: usize,
    pub realloc_count: usize,
    pub failed_count: usize,
    pub last_failed_size: usize,
    pub last_failed_align: usize,
}

struct KernelHeapAllocator {
    inner: LockedHeap<32>,
    capacity: AtomicUsize,
    current: AtomicUsize,
    peak: AtomicUsize,
    alloc_count: AtomicUsize,
    dealloc_count: AtomicUsize,
    realloc_count: AtomicUsize,
    failed_count: AtomicUsize,
    last_failed_size: AtomicUsize,
    last_failed_align: AtomicUsize,
}

static KERNEL_HEAP_RECLAIM_ACTIVE: AtomicBool = AtomicBool::new(false);

impl KernelHeapAllocator {
    pub const fn empty() -> Self {
        Self {
            inner: LockedHeap::empty(),
            capacity: AtomicUsize::new(0),
            current: AtomicUsize::new(0),
            peak: AtomicUsize::new(0),
            alloc_count: AtomicUsize::new(0),
            dealloc_count: AtomicUsize::new(0),
            realloc_count: AtomicUsize::new(0),
            failed_count: AtomicUsize::new(0),
            last_failed_size: AtomicUsize::new(0),
            last_failed_align: AtomicUsize::new(0),
        }
    }

    unsafe fn init(&self, start: usize, size: usize) {
        unsafe { self.inner.lock().init(start, size) };
        self.capacity.store(size, Ordering::Relaxed);
    }

    fn note_alloc(&self, size: usize) {
        let now = self
            .current
            .fetch_add(size, Ordering::Relaxed)
            .saturating_add(size);
        self.alloc_count.fetch_add(1, Ordering::Relaxed);
        self.update_peak(now);
    }

    fn note_dealloc(&self, size: usize) {
        let _ = self
            .current
            .fetch_update(Ordering::Relaxed, Ordering::Relaxed, |value| {
                Some(value.saturating_sub(size))
            });
        self.dealloc_count.fetch_add(1, Ordering::Relaxed);
    }

    fn note_realloc_success(&self, old_size: usize, new_size: usize) {
        let now = if new_size >= old_size {
            self.current
                .fetch_add(new_size - old_size, Ordering::Relaxed)
                .saturating_add(new_size - old_size)
        } else {
            let _ = self
                .current
                .fetch_update(Ordering::Relaxed, Ordering::Relaxed, |value| {
                    Some(value.saturating_sub(old_size - new_size))
                });
            self.current.load(Ordering::Relaxed)
        };
        self.realloc_count.fetch_add(1, Ordering::Relaxed);
        self.update_peak(now);
    }

    fn note_failed(&self, layout: Layout) {
        self.failed_count.fetch_add(1, Ordering::Relaxed);
        self.last_failed_size
            .store(layout.size(), Ordering::Relaxed);
        self.last_failed_align
            .store(layout.align(), Ordering::Relaxed);
    }

    fn try_begin_reclaim(&self) -> bool {
        KERNEL_HEAP_RECLAIM_ACTIVE
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
            .is_ok()
    }

    fn end_reclaim(&self) {
        KERNEL_HEAP_RECLAIM_ACTIVE.store(false, Ordering::Release);
    }

    fn reclaim_recycled_process_resources(&self) -> bool {
        if !self.try_begin_reclaim() {
            return false;
        }
        crate::process::drain_recycled_processes_for_heap_failure();
        crate::fs::drop_clean_block_cache_for_heap_failure(8192);
        self.end_reclaim();
        true
    }

    fn log_failure(&self, op: &str, requested_size: usize, requested_align: usize) {
        let heap = self.stats();
        let recycle = crate::process::debug_recycle_runtime_stats();
        let (mem_created, mem_dropped, mem_drop_pt) = memory_set_debug_counts();
        println!(
            "[kheap] FAILED op={} size={} align={} current={}/{} peak={} ops={}/{}/{} fail={}/{}/{} recycle_q={}/{} recycle_enq={}/{} recycle_drain={}/{} calls={}/{}/{}/{} last={}/{} backlog={}/{} mem_life={}/{} mem_drop_pt={}",
            op,
            requested_size,
            requested_align,
            heap.current,
            heap.capacity,
            heap.peak,
            heap.alloc_count,
            heap.dealloc_count,
            heap.realloc_count,
            heap.failed_count,
            heap.last_failed_size,
            heap.last_failed_align,
            recycle.queued_pcbs,
            recycle.queued_memsets,
            recycle.enqueued_pcbs,
            recycle.enqueued_memsets,
            recycle.drained_pcbs,
            recycle.drained_memsets,
            recycle.drain_calls,
            recycle.pressure_calls,
            recycle.heap_pressure_calls,
            recycle.heap_failure_calls,
            recycle.last_drain_pcbs,
            recycle.last_drain_memsets,
            recycle.last_backlog_pcbs,
            recycle.last_backlog_memsets,
            mem_created,
            mem_dropped,
            mem_drop_pt,
        );
    }

    fn update_peak(&self, value: usize) {
        let mut peak = self.peak.load(Ordering::Relaxed);
        while value > peak {
            match self
                .peak
                .compare_exchange_weak(peak, value, Ordering::Relaxed, Ordering::Relaxed)
            {
                Ok(_) => break,
                Err(observed) => peak = observed,
            }
        }
    }

    fn stats(&self) -> KernelHeapStats {
        KernelHeapStats {
            capacity: self.capacity.load(Ordering::Relaxed),
            current: self.current.load(Ordering::Relaxed),
            peak: self.peak.load(Ordering::Relaxed),
            alloc_count: self.alloc_count.load(Ordering::Relaxed),
            dealloc_count: self.dealloc_count.load(Ordering::Relaxed),
            realloc_count: self.realloc_count.load(Ordering::Relaxed),
            failed_count: self.failed_count.load(Ordering::Relaxed),
            last_failed_size: self.last_failed_size.load(Ordering::Relaxed),
            last_failed_align: self.last_failed_align.load(Ordering::Relaxed),
        }
    }
}

unsafe impl GlobalAlloc for KernelHeapAllocator {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        let mut ptr = unsafe { GlobalAlloc::alloc(&self.inner, layout) };
        if ptr.is_null() && self.reclaim_recycled_process_resources() {
            ptr = unsafe { GlobalAlloc::alloc(&self.inner, layout) };
        }
        if !ptr.is_null() {
            self.note_alloc(layout.size());
        } else {
            self.note_failed(layout);
            self.log_failure("alloc", layout.size(), layout.align());
        }
        ptr
    }

