// 初始化真实文件系统和 VFS 命名空间
pub fn init_filesystems() {
    ext4::init();

    // 注册 ramfs tmpfs procfs sysfs devfs ext4fs 等内置后端
    filesystems::register_builtin_filesystems();

    // 当前默认 root 是 ramfs demo root
    // 这里主动获取 root 会把 demo root 固定为 VFS_ROOT_MOUNT
    // 后续会设计成变成更贴近linux的 root
    let _ = vfs_core::api::vfs_api_root_path();

    // 在 demo root 的 /proc 和 /sys 上挂载伪文件系统
    let _ = vfs_core::api::vfs_api_mount_procfs_on_demo_root();
    let _ = vfs_core::api::vfs_api_mount_sysfs_on_demo_root();

    // 把测试盘 ext4 中的 /glibc 和 /musl 子树挂到当前 root 下
    // 当前比赛测试主要从这两个目录运行 busybox LTP lmbench iozone 等程序
    let _ = vfs_core::api::vfs_api_mount_test_roots_from_ext4();
}

// 初始化不依赖块设备的运行态状态
pub fn init_runtime_state() {
    filesystems::pipefs::init_runtime_state();
    vfs_core::api::vfs_api_init_mount_runtime_state();
}

// 清理测试残留运行状态
pub fn cleanup_test_runtime_state() {
    vfs_core::api::vfs_api_mmap_cleanup_shared_anon_frames();
    filesystems::pipefs::cleanup_pipe_buffers();
}

