    flags: u16,
    mtu: i32,
    addr: u32,
    netmask: u32,
}

impl Eth0Device {
    const fn new() -> Self {
        Self {
            ifindex: 2,
            flags: IFF_UP | IFF_RUNNING | IFF_BROADCAST | IFF_MULTICAST,
            mtu: 1500,
            addr: 0x0a00_020f,
            netmask: 0xffff_ff00,
        }
    }
}

static ETH0_DEVICE: Mutex<Eth0Device> = Mutex::new(Eth0Device::new());
static ETH0_IPV4_ADDRS: Mutex<Vec<u32>> = Mutex::new(Vec::new());

