pub fn eth0_primary_ipv4() -> u32 {
    ETH0_DEVICE.lock().addr
}

pub fn eth0_netmask() -> u32 {
    ETH0_DEVICE.lock().netmask
}

pub fn eth0_ipv4_addrs() -> Vec<u32> {
    let mut out = Vec::new();
    let primary = eth0_primary_ipv4();
    out.push(primary);
    let aliases = ETH0_IPV4_ADDRS.lock();
    for addr in aliases.iter().copied() {
        if !out.contains(&addr) {
            out.push(addr);
        }
    }
    out
}

pub fn eth0_has_ipv4(addr: u32) -> bool {
    eth0_ipv4_addrs().into_iter().any(|item| item == addr)
}

pub fn eth0_has_ipv4_alias(addr: u32) -> bool {
    ETH0_IPV4_ADDRS
        .lock()
        .iter()
        .copied()
        .any(|item| item == addr)
}

pub fn netif_has_local_ip(addr: smoltcp::wire::IpAddress) -> bool {
    match addr {
        smoltcp::wire::IpAddress::Ipv4(v4) => {
            let raw = u32::from_be_bytes(v4.octets());
            raw == 0 || (raw >> 24) == 127 || eth0_has_ipv4(raw)
        }
        smoltcp::wire::IpAddress::Ipv6(v6) => v6.is_unspecified() || v6.is_loopback(),
    }
}

fn eth0_add_ipv4_alias(addr: u32) {
    if addr == 0 {
        return;
    }
    let primary = eth0_primary_ipv4();
    if addr == primary {
        return;
    }
    let mut aliases = ETH0_IPV4_ADDRS.lock();
    if !aliases.contains(&addr) {
        aliases.push(addr);
    }
}

fn eth0_clear_ipv4_aliases() {
    ETH0_IPV4_ADDRS.lock().clear();
}

fn read_user_buffer(ptr: *const u8, len: usize) -> Option<alloc::vec::Vec<u8>> {
    if len == 0 {
        return Some(alloc::vec::Vec::new());
    }
    let pm = crate::process::PROCESS_MANAGER.lock();
    let pcb = pm.current_process()?;
    pcb.memory_set.copy_from_user(ptr, len)
}

fn write_user_buffer(ptr: *mut u8, user_len: usize, data: &[u8]) -> bool {
    let memory_set = {
        let pm = crate::process::PROCESS_MANAGER.lock();
        let Some(pcb) = pm.current_process() else {
            return false;
        };
        pcb.memory_set.clone()
    };
    if data.len() > user_len {
        return false;
    }
    memory_set.copy_to_user_checked(ptr, user_len, data)
}

fn parse_ifreq_name(raw: &[u8]) -> Result<String, isize> {
    if raw.len() < IFREQ_SIZE {
        return Err(EFAULT);
    }
    let end = raw[..IFNAMSIZ]
        .iter()
        .position(|byte| *byte == 0)
        .unwrap_or(IFNAMSIZ);
    let name = core::str::from_utf8(&raw[..end]).map_err(|_| EINVAL)?;
    Ok(name.into())
}

