            NetIfDevice::Loopback(dev) => dev.mtu,
            NetIfDevice::Eth0(dev) => dev.mtu,
        }
    }

    fn addr(self) -> u32 {
        match self {
            NetIfDevice::Loopback(dev) => dev.addr,
            NetIfDevice::Eth0(dev) => dev.addr,
        }
    }

    fn netmask(self) -> u32 {
        match self {
            NetIfDevice::Loopback(dev) => dev.netmask,
            NetIfDevice::Eth0(dev) => dev.netmask,
        }
    }

    fn broadcast(self) -> u32 {
        self.addr() | !self.netmask()
    }

    fn hw_family(self) -> u16 {
        match self {
            NetIfDevice::Loopback(_) => ARPHRD_LOOPBACK,
            NetIfDevice::Eth0(_) => ARPHRD_ETHER,
