fn write_sigtimedwait_info_to_process(
    pid: usize,
    info_ptr: usize,
    signo: i32,
) -> Result<(), isize> {
    if info_ptr == 0 {
        return Ok(());
    }
    let siginfo = take_pending_siginfo(pid, signo).unwrap_or(CompatSigInfo {
        si_signo: signo,
        si_errno: 0,
        si_code: SI_TKILL,
        si_pid: current_tgid() as i32,
        si_uid: 0,
        ..CompatSigInfo::default()
    });
    let bytes = unsafe {
        core::slice::from_raw_parts(
            &siginfo as *const CompatSigInfo as *const u8,
            core::mem::size_of::<CompatSigInfo>(),
        )
    };
    let mut pm = PROCESS_MANAGER.lock();
    let Some(pcb) = pm.get_process_mut(pid) else {
        return Err(-EFAULT);
    };
    if !pcb.memory_set.copy_to_user(info_ptr as *mut u8, bytes) {
        return Err(-EFAULT);
    }
    Ok(())
}

fn finish_sigtimedwait_signal(info: *mut u8, pid: usize, signo: i32) -> isize {
    match write_sigtimedwait_info_to_process(pid, info as usize, signo) {
        Ok(()) => signo as isize,
        Err(e) => e,
    }
}

fn build_compat_ucontext(saved: &TrapContext, old_mask: u64) -> CompatUContext {
    let mut uc = CompatUContext::default();
    uc.uc_sigmask.bits[0] = old_mask;
    saved.export_signal_gregs(&mut uc.uc_mcontext.gregs);
    uc
}

fn install_signal_frame(
    saved: &TrapContext,
    signo: i32,
    old_mask: u64,
) -> Result<(usize, usize, usize), isize> {
    // glibc's SIGCANCEL handler validates si_pid against __getpid(), i.e. the
    // thread-group ID instead of the sender TID. We build signal frames in the
    // target thread's context, so use current_tgid() here to preserve that ABI.
    let sender_pid = current_tgid() as i32;
    let target_pid = current_pid();
    let mut pm = PROCESS_MANAGER.lock();
    let Some(pcb) = pm.current_process_mut() else {
        return Err(-EFAULT);
    };

    // 当前未实现完整 altstack；frame 直接压到用户当前 sp 下方，并写入 siginfo/ucontext。
    let frame_size = core::mem::size_of::<CompatSigInfo>() + core::mem::size_of::<CompatUContext>();
    let frame_top = align_down(trap_stack_pointer(saved), SIGNAL_FRAME_ALIGN);
    let frame_bottom = align_down(frame_top.saturating_sub(frame_size), SIGNAL_FRAME_ALIGN);
    if frame_bottom < 0x1000 {
        return Err(-EFAULT);
    }

    let siginfo = take_pending_siginfo(target_pid, signo).unwrap_or(CompatSigInfo {
        si_signo: signo,
        si_errno: 0,
        si_code: SI_TKILL,
        si_pid: sender_pid,
        si_uid: 0,
        ..CompatSigInfo::default()
    });
    let ucontext = build_compat_ucontext(saved, old_mask);

    let siginfo_bytes = unsafe {
        core::slice::from_raw_parts(
            &siginfo as *const CompatSigInfo as *const u8,
            core::mem::size_of::<CompatSigInfo>(),
        )
    };
    if !pcb
        .memory_set
        .copy_to_user(frame_bottom as *mut u8, siginfo_bytes)
    {
        return Err(-EFAULT);
    }

    let ucontext_addr = frame_bottom + core::mem::size_of::<CompatSigInfo>();
    let ucontext_bytes = unsafe {
        core::slice::from_raw_parts(
            &ucontext as *const CompatUContext as *const u8,
            core::mem::size_of::<CompatUContext>(),
        )
    };
    if !pcb
        .memory_set
        .copy_to_user(ucontext_addr as *mut u8, ucontext_bytes)
    {
        return Err(-EFAULT);
    }

    Ok((frame_bottom, ucontext_addr, frame_bottom))
}

fn read_current_user_bytes(ptr: *const u8, len: usize) -> Result<Vec<u8>, isize> {
    if ptr.is_null() {
        return Err(-EFAULT);
    }
    let pm = PROCESS_MANAGER.lock();
    let pcb = pm.current_process().ok_or(-EFAULT)?;
    pcb.memory_set.copy_from_user(ptr, len).ok_or(-EFAULT)
}

fn write_current_user_bytes(ptr: *mut u8, bytes: &[u8]) -> Result<(), isize> {
    if ptr.is_null() {
        return Err(-EFAULT);
    }
    let mut pm = PROCESS_MANAGER.lock();
    let pcb = pm.current_process_mut().ok_or(-EFAULT)?;
    if pcb.memory_set.copy_to_user(ptr, bytes) {
        Ok(())
    } else {
        Err(-EFAULT)
    }
}

fn read_sigset_word(ptr: *const u8, sigsetsize: usize) -> Result<u64, isize> {
    if ptr.is_null() {
        return Err(-EFAULT);
    }
    if sigsetsize == 0 {
        return Err(-EINVAL);
    }
    let read_len = core::cmp::min(sigsetsize, core::mem::size_of::<u64>());
    let bytes = read_current_user_bytes(ptr, read_len)?;
    let mut word = [0u8; 8];
    word[..read_len].copy_from_slice(&bytes[..read_len]);
    Ok(u64::from_le_bytes(word))
}

fn write_sigset_word(ptr: *mut u8, sigsetsize: usize, mask: u64) -> Result<(), isize> {
    if ptr.is_null() {
        return Ok(());
    }
    if sigsetsize == 0 {
        return Err(-EINVAL);
    }
    let write_len = core::cmp::min(sigsetsize, core::mem::size_of::<u64>());
    let bytes = mask.to_le_bytes();
    write_current_user_bytes(ptr, &bytes[..write_len])
}

pub(crate) fn install_temporary_signal_mask(
    set: *const u8,
    sigsetsize: usize,
) -> Result<Option<u64>, isize> {
    if set.is_null() {
        return Ok(None);
    }
    // ppoll/pselect/epoll_pwait 使用临时 mask：进入等待前安装，返回或被唤醒后恢复。
    let new_mask = read_sigset_word(set, sigsetsize)?;
    let pid = current_pid();
    let mut masks = SIGNAL_MASKS.lock();
    let old_mask = *masks.get(&pid).unwrap_or(&0);
    if new_mask == 0 {
        masks.remove(&pid);
    } else {
        masks.insert(pid, new_mask);
    }
    Ok(Some(old_mask))
}

