pub(crate) fn clear_process_runtime_state(pid: usize, tgid: usize) {
    // pid 可能被复用；退出时必须清掉按 pid/tgid 索引的 syscall 辅助状态，
    // 否则后续进程可能继承旧 rusage、comm、prctl 等兼容状态。
    time::clear_process_rusage(pid, tgid);
    process::clear_process_misc_runtime_state(pid, tgid);
    crate::process::clear_comm_name(pid);
}

